"""Download Noto Color Emoji PNGs for dashboard status icons.

Source: Google Noto Color Emoji (https://github.com/googlefonts/noto-emoji)
License: Apache License 2.0 (https://github.com/googlefonts/noto-emoji/blob/main/LICENSE)

Usage:
    python scripts/download_emoji.py
"""

import os
import sys
import urllib.request
from pathlib import Path

BASE_URL = "https://raw.githubusercontent.com/googlefonts/noto-emoji/main/png/128"
ASSETS_DIR = Path(__file__).resolve().parent.parent / "claude_dashboard" / "assets"

# Map local filenames to Noto codepoint filenames
EMOJI_MAP = {
    "emoji_working.png": "emoji_u1f504.png",  # 🔄
    "emoji_ready.png": "emoji_u23f8.png",  # ⏸️
    "emoji_idle.png": "emoji_u23f8.png",  # ⏸️ (same as ready)
    "emoji_awaiting_input.png": "emoji_u2753.png",  # ❓
    "emoji_permission_required.png": "emoji_u26a0.png",  # ⚠️
    "emoji_unattached.png": "emoji_u1f47b.png",  # 👻
}


def main():
    ASSETS_DIR.mkdir(parents=True, exist_ok=True)
    failed = []

    for local_name, remote_name in EMOJI_MAP.items():
        dest = ASSETS_DIR / local_name
        url = f"{BASE_URL}/{remote_name}"
        try:
            urllib.request.urlretrieve(url, dest)
            size = os.path.getsize(dest)
            print(f"  OK  {local_name} ({size:,} bytes)")
        except Exception as e:
            print(f"  FAIL {local_name}: {e}", file=sys.stderr)
            failed.append(local_name)

    if failed:
        print(f"\n{len(failed)} download(s) failed.", file=sys.stderr)
        sys.exit(1)

    print(f"\nAll {len(EMOJI_MAP)} emoji downloaded to {ASSETS_DIR}")


if __name__ == "__main__":
    main()
